module top_module(
    input invalid_a,
    input [2:0] state,    // 3-bit one-hot current state
    output reg X_next,
    output reg Y_next,
    output reg Z_next,
    output reg b,
    output reg c
 );parameter X=0, Y=1, Z=2;

	assign X_next = state[Y]&invalid_a | state[Z]&~invalid_a;
	assign Y_next = state[X]&~invalid_a | state[Z]&invalid_a;
	assign Z_next = state[X]&invalid_a | state[Y]&~invalid_a;

	assign b = state[Y];
	assign c = state[Z];

endmodule
